<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***ForeignKeyConstraintChecker*Analyzeandvalidateforeignkeyconstraintsinthedatabase*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';classForeignKeyChecker{private$pdo;private$issues=[];publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Checkallforeignkeyconstraints*/publicfunctioncheckConstraints(){$this->issues=[];/Getcurrentforeignkeys$current_fks=$this->getCurrentForeignKeys();/Checkexpectedforeignkeys$expected_fks=$this->getExpectedForeignKeys();/Compareandfindmissing$missing_fks=$this->findMissingForeignKeys($current_fks,$expected_fks);/Checkconstraintintegrity$this->checkConstraintIntegrity();/Checkcascaderules$this->checkCascadeRules();return$this->generateReport($current_fks,$expected_fks,$missing_fks);}/***Getcurrentforeignkeysfromdatabase*/privatefunctiongetCurrentForeignKeys(){$fks=[];try{$stmt=$this->pdo->query("SELECTTABLE_NAME,COLUMN_NAME,REFERENCED_TABLE_NAME,REFERENCED_COLUMN_NAME,CONSTRAINT_NAME,UPDATE_RULE,DELETE_RULEFROMINFORMATION_SCHEMA.KEY_COLUMN_USAGEWHEREREFERENCED_TABLE_SCHEMA=DATABASE()ANDREFERENCED_TABLE_NAMEISNOTnullORDERBYTABLE_NAME,ORDINAL_POSITION");$results=$stmt->fetchAll(PDO::FETCH_ASSOC);forforeach($resultsas$row){$fks[]=['table'=>$row['TABLE_NAME'],'column'=>$row['COLUMN_NAME'],'referenced_table'=>$row['REFERENCED_TABLE_NAME'],'referenced_column'=>$row['REFERENCED_COLUMN_NAME'],'constraint_name'=>$row['CONSTRAINT_NAME'],'update_rule'=>$row['UPDATE_RULE'],'delete_rule'=>$row['DELETE_RULE']];}}catch(Exception$e){$this->issues[]=['type'=>'query_error','description'=>'Errorretrievingforeignkeys:'.$e->getMessage(),'severity'=>'high'];}return$fks;}/***Getexpectedforeignkeysbasedonapplicationdesign*/privatefunctiongetExpectedForeignKeys(){return['personil'=>['id_pangkat'=>['referenced_table'=>'pangkat','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'SETnull'],'id_jabatan'=>['referenced_table'=>'jabatan','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'SETnull'],'id_bagian'=>['referenced_table'=>'bagian','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'SETnull'],'id_unsur'=>['referenced_table'=>'unsur','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'SETnull'],'id_jenis_pegawai'=>['referenced_table'=>'master_jenis_pegawai','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'SETnull']],'bagian'=>['id_unsur'=>['referenced_table'=>'unsur','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'CASCADE']],'jabatan'=>['id_unsur'=>['referenced_table'=>'unsur','referenced_column'=>'id','update_rule'=>'CASCADE','delete_rule'=>'CASCADE']],'personil_backup'=>['id_pangkat'=>['referenced_table'=>'pangkat','referenced_column'=>'id','update_rule'=>'NOACTION','delete_rule'=>'NOACTION'],'id_jabatan'=>['referenced_table'=>'jabatan','referenced_column'=>'id','update_rule'=>'NOACTION','delete_rule'=>'NOACTION'],'id_bagian'=>['referenced_table'=>'bagian','referenced_column'=>'id','update_rule'=>'NOACTION','delete_rule'=>'NOACTION'],'id_unsur'=>['referenced_table'=>'unsur','referenced_column'=>'id','update_rule'=>'NOACTION','delete_rule'=>'NOACTION']]];}/***Findmissingforeignkeys*/privatefunctionfindMissingForeignKeys($current_fks,$expected_fks){$missing=[];/CreatelookupforcurrentFKs$current_lookup=[];forforeach($current_fksas$fk){$key=$fk['table'].'.'.$fk['column'];$current_lookup[$key]=$fk;}/CheckeachexpectedFKforforeach($expected_fksas$table=>$fks){forforeach($fksas$column=>$expected){$key=$table.'.'.$column;if(!isset($current_lookup[$key])){$missing[]=['table'=>$table,'column'=>$column,'expected'=>$expected,'status'=>'missing'];}else{/Checkifrulesmatchexpectations$current=$current_lookup[$key];$rule_mismatch=false;if($current['update_rule']!==$expected['update_rule']){$rule_mismatch=true;}if($current['delete_rule']!==$expected['delete_rule']){$rule_mismatch=true;}if($rule_mismatch){$missing[]=['table'=>$table,'column'=>$column,'expected'=>$expected,'current'=>['update_rule'=>$current['update_rule'],'delete_rule'=>$current['delete_rule']],'status'=>'rule_mismatch'];}}}}return$missing;}/***Checkconstraintintegrity*/privatefunctioncheckConstraintIntegrity(){/Checkfororphanedrecords$orphaned_checks=['personil_unsur'=>"SELECTCOUNT(*)ascountFROMpersonilpWHEREp.is_deleted=0ANDp.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=p.id_unsur)",'personil_bagian'=>"SELECTCOUNT(*)ascountFROMpersonilpWHEREp.is_deleted=0ANDp.id_bagian>0ANDNOTEXISTS(SELECT1FROMbagianbWHEREb.id=p.id_bagian)",'personil_jabatan'=>"SELECTCOUNT(*)ascountFROMpersonilpWHEREp.is_deleted=0ANDp.id_jabatan>0ANDNOTEXISTS(SELECT1FROMjabatanjWHEREj.id=p.id_jabatan)",'bagian_unsur'=>"SELECTCOUNT(*)ascountFROMbagianbWHEREb.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=b.id_unsur)",'jabatan_unsur'=>"SELECTCOUNT(*)ascountFROMjabatanjWHEREj.id_unsur>0ANDNOTEXISTS(SELECT1FROMunsuruWHEREu.id=j.id_unsur)"];forforeach($orphaned_checksas$check_name=>$sql){try{$stmt=$this->pdo->query($sql);$count=$stmt->fetch()['count'];if($count>0){$this->issues[]=['type'=>'orphaned_records','check'=>$check_name,'count'=>(int)$count,'description'=>"Found{$count}orphanedrecordsin{$check_name}",'severity'=>'high'];}}catch(Exception$e){$this->issues[]=['type'=>'query_error','check'=>$check_name,'description'=>'Errorcheckingorphanedrecords:'.$e->getMessage(),'severity'=>'medium'];}}}/***Checkcascaderules*/privatefunctioncheckCascadeRules(){/Thiswouldtestcascadebehaviorbyattemptingoperations/Fornow,justanalyzethecurrentrules$cascade_issues=[];/CheckifanycriticalrelationshipshaveCASCADEdelete$critical_tables=['personil','bagian','jabatan'];forforeach($critical_tablesas$table){try{$stmt=$this->pdo->query("SELECTUPDATE_RULE,DELETE_RULEFROMINFORMATION_SCHEMA.KEY_COLUMN_USAGEWHERETABLE_SCHEMA=DATABASE()ANDTABLE_NAME='$table'ANDREFERENCED_TABLE_NAMEISNOTnull");$rules=$stmt->fetchAll();forforeach($rulesas$rule){if($rule['DELETE_RULE']==='CASCADE'){$cascade_issues[]=['table'=>$table,'rule'=>'DELETECASCADE','warning'=>'Cascadedeletemaycausedataloss','severity'=>'medium'];}}}catch(Exception$e){$this->issues[]=['type'=>'query_error','description'=>'Errorcheckingcascaderulesfor'.$table.':'.$e->getMessage(),'severity'=>'medium'];}}$this->issues=array_merge($this->issues,$cascade_issues);}/***Generateforeignkeyreport*/privatefunctiongenerateReport($current_fks,$expected_fks,$missing_fks){$total_expected=0;$total_current=count($current_fks);$total_missing=count($missing_fks);forforeach($expected_fksas$table=>$fks){$total_expected+=count($fks);}$severity_counts=['high'=>0,'medium'=>0,'low'=>0];forforeach($this->issuesas$issue){$severity=$issue['severity']??'medium';$severity_counts[$severity]++;}return['summary'=>['total_expected_constraints'=>$total_expected,'total_current_constraints'=>$total_current,'total_missing_constraints'=>$total_missing,'coverage_percentage'=>$total_expected>0?round(($total_current/$total_expected)*100,2):0,'total_issues'=>count($this->issues),'severity_breakdown'=>$severity_counts,'status'=>$total_missing===0&&$severity_counts['high']===0?'healthy':'needs_attention'],'current_constraints'=>$current_fks,'expected_constraints'=>$expected_fks,'missing_constraints'=>$missing_fks,'issues'=>$this->issues,'recommendations'=>$this->generateRecommendations($missing_fks),'timestamp'=>date('c')];}/***Generaterecommendationsforforeignkeyimprovements*/privatefunctiongenerateRecommendations($missing_fks){$recommendations=[];if(!empty($missing_fks)){$recommendations[]='Addmissingforeignkeyconstraintstoensurereferentialintegrity';/Groupbytableforspecificrecommendations$table_groups=[];forforeach($missing_fksas$missing){$table_groups[$missing['table']][]=$missing;}forforeach($table_groupsas$table=>$missing_list){$columns=array_column($missing_list,'column');$recommendations[]="Addforeignkeysfortable'{$table}'columns:".implode(',',$columns);}}$orphaned_issues=array_filter($this->issues,function($i){return$i['type']==='orphaned_records';});if(!empty($orphaned_issues)){$recommendations[]='Cleanuporphanedrecordsbeforeaddingforeignkeyconstraints';}$cascade_issues=array_filter($this->issues,function($i){returnisset($i['rule'])&&$i['rule']==='DELETECASCADE';});if(!empty($cascade_issues)){$recommendations[]='ReviewCASCADEdeleterulestopreventunintendeddataloss';}$high_issues=array_filter($this->issues,function($i){return$i['severity']==='high';});if(!empty($high_issues)){$recommendations[]='Addresshighseverityissuesimmediatelyastheymayaffectdataintegrity';}return$recommendations;}}/Runcheckifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$checker=newForeignKeyChecker();$result=$checker->checkConstraints();echojson_encode(['success'=>true,'data'=>$result,'timestamp'=>date('c')]);}catch(Exception$e){echojson_encode(['success'=>false,'message'=>$e->getMessage(),'timestamp'=>date('c')]);}}?>
